import hashlib

def encrypt_credit_card(cc_number):
    # Use a fast encryption method such as SHA-256 to encrypt the credit card number
    encrypted_cc = hashlib.sha256(cc_number.encode()).hexdigest()
    return encrypted_cc

def decrypt_credit_card(encrypted_cc):
    # Use a fast encryption method such as SHA-256 to decrypt the credit card number
    decrypted_cc = hashlib.sha256(encrypted_cc.encode()).hexdigest()
    return decrypted_cc